}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_f8b37f04c79e40268d181b2e2152e49b.Data
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Only administrators can view this page.</p>

@if (users is null)
{
    <p><em>Loading users...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.DisplayName</td>
                    <td>@user.Email</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(ApplicationUser, IList<string>)>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }
        users = result;
    }
}

